import type { Metadata } from "next";
import type { ReactNode } from "react";

import "./globals.css";

export const metadata: Metadata = {
  description: "Demo Next.js workspace app for shared addition logic.",
  title: "Addition Workspace Demo",
};

type RootLayoutProps = {
  children: ReactNode;
};

export default function RootLayout({ children }: RootLayoutProps) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );

import AdditionVisualizer from "../src/components/AdditionVisualizer";

export default function Page() {
  return (
    <main>
      <AdditionVisualizer />
    </main>
  );
}

:root {
  color-scheme: light;
  font-family: Inter, Arial, Helvetica, sans-serif;
  background: #f4f6fb;
  color: #101828;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  background:
    radial-gradient(circle at top, rgba(96, 165, 250, 0.18), transparent 36%),
